export const TERMS = [
  // ── Social & Cognitive Learning (6) ──
  { term:"Social learning theory", def:"The theory that we learn social behaviors by observing and imitating others, and by being influenced by whether those behaviors are reinforced or punished.", cat:"Social & Cognitive Learning", blank:"observing and imitating", accept:["social learning theory","bandura's theory"], example:"A child watches an older sibling get praised for sharing toys, so the child starts sharing too." },
  { term:"Vicarious conditioning", def:"Learning to associate a behavior with its consequences by observing what happens to others who perform that behavior.", cat:"Social & Cognitive Learning", blank:"observing what happens to others", accept:["vicarious conditioning","vicarious reinforcement","vicarious learning"], example:"After watching a classmate get detention for talking in class, you stay quiet to avoid the same punishment." },
  { term:"Modeling", def:"The process of observing and imitating a specific behavior demonstrated by another person (a model).", cat:"Social & Cognitive Learning", blank:"observing and imitating", accept:["modeling","modelling","observational learning"], example:"A young basketball player watches game film of a professional and copies their shooting form." },
  { term:"Insight learning", def:"A sudden realization of how to solve a problem without trial-and-error, involving a cognitive 'aha' moment.", cat:"Social & Cognitive Learning", blank:"sudden realization", accept:["insight learning","insight"], example:"After staring at a puzzle for minutes, the solution suddenly clicks and you solve it in one move — Köhler's apes stacking boxes to reach bananas." },
  { term:"Latent learning", def:"Learning that occurs without apparent reinforcement and is not demonstrated until there is an incentive to do so.", cat:"Social & Cognitive Learning", blank:"without apparent reinforcement", accept:["latent learning"], example:"Tolman's rats explored a maze without reward, yet once food was introduced they quickly navigated to it — they had learned the layout all along." },
  { term:"Cognitive maps", def:"Mental representations of a physical space or layout, used to navigate and plan routes.", cat:"Social & Cognitive Learning", blank:"mental representations", accept:["cognitive maps","cognitive map"], example:"You can give someone directions to your school without looking at a map because you have a cognitive map of your neighborhood." },

  // ── Classical Conditioning (15) ──
  { term:"Behavioral perspective", def:"A psychological approach that emphasizes the study of observable behavior and the role of the environment in shaping behavior through conditioning.", cat:"Classical Conditioning", blank:"observable behavior", accept:["behavioral perspective","behaviorism","behaviourism"], example:"A behaviorist would explain a child's fear of dogs not through inner feelings, but through a past negative experience with a dog." },
  { term:"Classical conditioning", def:"A type of learning in which an organism comes to associate two stimuli — a neutral stimulus that comes to signal an unconditioned stimulus — and begins to produce a response in anticipation.", cat:"Classical Conditioning", blank:"associate two stimuli", accept:["classical conditioning","pavlovian conditioning","respondent conditioning"], example:"Pavlov's dogs learned to salivate at the sound of a bell because the bell had been repeatedly paired with food." },
  { term:"Association", def:"In learning theory, the mental connection formed between two events, stimuli, or ideas that occur together.", cat:"Classical Conditioning", blank:"mental connection", accept:["association"], example:"After getting sick from eating sushi, you form an association between sushi and nausea." },
  { term:"Acquisition", def:"The initial stage of learning in which a response is first established and gradually strengthened through repeated pairings.", cat:"Classical Conditioning", blank:"first established", accept:["acquisition"], example:"During acquisition, a dog gradually learns to salivate to a bell as it is paired with food over many trials." },
  { term:"Associative learning", def:"Learning that certain events occur together, including both classical conditioning and operant conditioning.", cat:"Classical Conditioning", blank:"events occur together", accept:["associative learning"], example:"A cat learns that the sound of a can opener (event 1) is followed by being fed (event 2) and starts running to the kitchen." },
  { term:"Unconditioned stimulus (UCS)", def:"A stimulus that naturally and automatically triggers a response without any prior learning.", cat:"Classical Conditioning", blank:"naturally and automatically", accept:["unconditioned stimulus","ucs","us"], example:"Food in a dog's mouth is an unconditioned stimulus because it naturally causes salivation without training." },
  { term:"Unconditioned response (UR)", def:"The unlearned, naturally occurring response to an unconditioned stimulus.", cat:"Classical Conditioning", blank:"unlearned, naturally occurring", accept:["unconditioned response","ur","ucr"], example:"Salivating when food is placed in your mouth is an unconditioned response — no learning is required." },
  { term:"Conditioned response (CR)", def:"A learned response to a previously neutral stimulus that has been paired with an unconditioned stimulus.", cat:"Classical Conditioning", blank:"learned response", accept:["conditioned response","cr"], example:"After conditioning, Pavlov's dogs salivated at the sound of a bell alone — the salivation to the bell is the conditioned response." },
  { term:"Conditioned stimulus (CS)", def:"An originally neutral stimulus that, after association with an unconditioned stimulus, comes to trigger a conditioned response.", cat:"Classical Conditioning", blank:"originally neutral", accept:["conditioned stimulus","cs"], example:"The bell in Pavlov's experiment started as a neutral stimulus but became a conditioned stimulus that triggered salivation." },
  { term:"Extinction", def:"The diminishing of a conditioned response when the conditioned stimulus is repeatedly presented without the unconditioned stimulus.", cat:"Classical Conditioning", blank:"diminishing", accept:["extinction"], example:"If the bell is rung many times without food, the dog gradually stops salivating to the bell." },
  { term:"Spontaneous recovery", def:"The reappearance, after a pause, of an extinguished conditioned response.", cat:"Classical Conditioning", blank:"reappearance", accept:["spontaneous recovery"], example:"Days after extinction, the dog hears the bell again and briefly salivates — the response has spontaneously recovered." },
  { term:"Stimulus discrimination", def:"The learned ability to distinguish between a conditioned stimulus and stimuli that do not signal an unconditioned stimulus.", cat:"Classical Conditioning", blank:"distinguish", accept:["stimulus discrimination"], example:"A dog salivates to a high-pitched tone paired with food but not to a low-pitched tone that was never paired with food." },
  { term:"Stimulus generalization", def:"The tendency for stimuli similar to the conditioned stimulus to elicit similar responses.", cat:"Classical Conditioning", blank:"similar to the conditioned stimulus", accept:["stimulus generalization"], example:"Little Albert feared not only white rats but also rabbits, fur coats, and Santa's beard — he generalized his fear." },
  { term:"Higher-order conditioning", def:"A procedure in which a well-established conditioned stimulus is paired with a new neutral stimulus, causing the new stimulus to also elicit the conditioned response.", cat:"Classical Conditioning", blank:"well-established conditioned stimulus", accept:["higher-order conditioning","second-order conditioning"], example:"After a dog learns to salivate to a bell, pairing a light with the bell can cause the dog to eventually salivate to the light alone." },
  { term:"Counterconditioning", def:"A technique that pairs a conditioned stimulus with a new response that is incompatible with the unwanted conditioned response.", cat:"Classical Conditioning", blank:"incompatible", accept:["counterconditioning","counter-conditioning"], example:"A person with a spider phobia is gradually exposed to spiders while practicing deep relaxation, replacing fear with calm." },

  // ── Biological Learning (5) ──
  { term:"Taste aversion", def:"A learned avoidance of a specific food resulting from a single pairing of that food with illness, even if the illness occurs hours later.", cat:"Biological Learning", blank:"single pairing", accept:["taste aversion","conditioned taste aversion","garcia effect"], example:"After getting food poisoning from shrimp, you feel nauseous just thinking about eating shrimp — even years later." },
  { term:"One-trial conditioning", def:"A form of classical conditioning in which a strong conditioned response is established after just a single pairing of a stimulus with an unconditioned stimulus.", cat:"Biological Learning", blank:"single pairing", accept:["one-trial conditioning","one trial conditioning"], example:"A child touches a hot stove once and immediately learns to fear touching it again." },
  { term:"Biological preparedness", def:"The innate predisposition of organisms to more easily learn associations that have survival value, as proposed by Seligman.", cat:"Biological Learning", blank:"innate predisposition", accept:["biological preparedness","preparedness"], example:"Humans develop phobias of snakes and spiders much more easily than phobias of flowers or cars, because fearing predators aided survival." },
  { term:"One-trial learning", def:"Learning that occurs from a single experience, particularly when the experience is intense or biologically significant.", cat:"Biological Learning", blank:"single experience", accept:["one-trial learning","one trial learning"], example:"A monkey that is shocked once after touching a specific object avoids that object permanently." },
  { term:"Habituation", def:"A form of non-associative learning in which an organism decreases its response to a repeated, harmless stimulus over time.", cat:"Biological Learning", blank:"decreases its response", accept:["habituation"], example:"You stop noticing the ticking of a clock after being in the room for a few minutes." },

  // ── Operant Conditioning (16) ──
  { term:"Operant conditioning", def:"A type of learning in which behavior is strengthened if followed by a reinforcer or diminished if followed by a punisher.", cat:"Operant Conditioning", blank:"strengthened if followed by a reinforcer", accept:["operant conditioning","instrumental conditioning"], example:"A rat learns to press a lever because doing so produces a food pellet (reinforcement)." },
  { term:"Reinforcement", def:"Any event that strengthens or increases the likelihood of a behavior it follows.", cat:"Operant Conditioning", blank:"strengthens", accept:["reinforcement"], example:"Giving a dog a treat after it sits on command increases the likelihood the dog will sit again." },
  { term:"Punishment", def:"Any event that decreases the likelihood of a behavior it follows.", cat:"Operant Conditioning", blank:"decreases", accept:["punishment"], example:"A teenager loses car privileges after breaking curfew, making them less likely to break curfew again." },
  { term:"Law of Effect", def:"Thorndike's principle that behaviors followed by favorable consequences become more likely, and behaviors followed by unfavorable consequences become less likely.", cat:"Operant Conditioning", blank:"favorable consequences", accept:["law of effect","thorndike's law of effect"], example:"Thorndike's cat learned to escape a puzzle box faster over repeated trials because the successful behavior (pulling a lever) was followed by freedom and food." },
  { term:"Positive reinforcement", def:"Increasing the likelihood of a behavior by presenting a desirable stimulus after the behavior occurs.", cat:"Operant Conditioning", blank:"presenting a desirable stimulus", accept:["positive reinforcement"], example:"A teacher gives a student a sticker for completing homework, making the student more likely to complete it again." },
  { term:"Negative reinforcement", def:"Increasing the likelihood of a behavior by removing an aversive stimulus when the behavior occurs.", cat:"Operant Conditioning", blank:"removing an aversive stimulus", accept:["negative reinforcement"], example:"Taking an aspirin removes your headache, so you're more likely to take aspirin when you have a headache in the future." },
  { term:"Positive punishment", def:"Decreasing the likelihood of a behavior by presenting an aversive stimulus after the behavior occurs.", cat:"Operant Conditioning", blank:"presenting an aversive stimulus", accept:["positive punishment"], example:"A child touches a hot stove and gets burned, making them less likely to touch it again." },
  { term:"Negative punishment", def:"Decreasing the likelihood of a behavior by removing a desirable stimulus after the behavior occurs.", cat:"Operant Conditioning", blank:"removing a desirable stimulus", accept:["negative punishment"], example:"A parent takes away a teenager's phone after they talk back, reducing the talking-back behavior." },
  { term:"Primary reinforcers", def:"Innately reinforcing stimuli that satisfy a biological need, such as food, water, or warmth.", cat:"Operant Conditioning", blank:"biological need", accept:["primary reinforcers","primary reinforcer"], example:"A hungry animal will work for food without being taught that food is desirable — it's a primary reinforcer." },
  { term:"Secondary reinforcers", def:"Stimuli that gain their reinforcing power through association with primary reinforcers; also called conditioned reinforcers.", cat:"Operant Conditioning", blank:"association with primary reinforcers", accept:["secondary reinforcers","secondary reinforcer","conditioned reinforcers"], example:"Money is a secondary reinforcer — it has no biological value but can be exchanged for food, shelter, and other primary reinforcers." },
  { term:"Reinforcement discrimination", def:"The ability to distinguish between situations in which a behavior will or will not be reinforced.", cat:"Operant Conditioning", blank:"distinguish between situations", accept:["reinforcement discrimination"], example:"A child learns to ask for candy at grandma's house (where it's reinforced) but not at school (where it isn't)." },
  { term:"Reinforcement generalization", def:"The tendency for a behavior reinforced in one situation to occur in similar situations.", cat:"Operant Conditioning", blank:"similar situations", accept:["reinforcement generalization"], example:"A child praised for saying 'please' at home starts saying 'please' at school and at friends' houses too." },
  { term:"Shaping", def:"An operant conditioning procedure in which reinforcers successively guide behavior toward closer and closer approximations of the desired behavior.", cat:"Operant Conditioning", blank:"closer approximations", accept:["shaping","successive approximations"], example:"Training a dog to roll over by first rewarding it for lying down, then for turning on its side, then for completing the full roll." },
  { term:"Instinctive drift", def:"The tendency of an organism to revert to innate, biologically predisposed behaviors that interfere with conditioned responses.", cat:"Operant Conditioning", blank:"revert to innate", accept:["instinctive drift"], example:"Raccoons trained to drop coins into a piggy bank begin rubbing the coins together instead, reverting to their natural food-washing behavior." },
  { term:"Superstitious behavior", def:"A behavior that is repeated because it was accidentally reinforced, even though it has no real effect on the outcome.", cat:"Operant Conditioning", blank:"accidentally reinforced", accept:["superstitious behavior","superstitious behaviour"], example:"A baseball player wears the same unwashed socks every game because he once hit a home run while wearing them." },
  { term:"Learned helplessness", def:"The hopelessness and passive resignation an organism learns when unable to avoid repeated aversive events.", cat:"Operant Conditioning", blank:"hopelessness and passive resignation", accept:["learned helplessness"], example:"Seligman's dogs that received inescapable shocks later failed to escape when escape was possible — they had learned helplessness." },

  // ── Reinforcement Schedules (8) ──
  { term:"Reinforcement schedules", def:"Patterns defining how often and on what basis reinforcers are delivered following a desired behavior.", cat:"Reinforcement Schedules", blank:"how often", accept:["reinforcement schedules","schedules of reinforcement"], example:"A factory might pay workers per hour (interval) or per unit produced (ratio) — these are different reinforcement schedules." },
  { term:"Continuous reinforcement", def:"A reinforcement schedule in which every occurrence of the desired behavior is reinforced.", cat:"Reinforcement Schedules", blank:"every occurrence", accept:["continuous reinforcement"], example:"A vending machine reinforces every coin insertion with a snack — that's continuous reinforcement." },
  { term:"Partial reinforcement", def:"A reinforcement schedule in which only some occurrences of the desired behavior are reinforced, producing behavior that is more resistant to extinction.", cat:"Reinforcement Schedules", blank:"only some occurrences", accept:["partial reinforcement","intermittent reinforcement"], example:"A slot machine pays out on only some pulls, yet people keep playing — partial reinforcement makes behavior resistant to extinction." },
  { term:"Fixed interval", def:"A reinforcement schedule that reinforces a response after a fixed amount of time has passed since the last reinforcement.", cat:"Reinforcement Schedules", blank:"fixed amount of time", accept:["fixed interval","fixed-interval schedule","fi"], example:"An employee receives a paycheck every two weeks regardless of how much work was done — that's a fixed-interval schedule." },
  { term:"Variable interval", def:"A reinforcement schedule that reinforces a response after varying and unpredictable amounts of time.", cat:"Reinforcement Schedules", blank:"varying and unpredictable amounts of time", accept:["variable interval","variable-interval schedule","vi"], example:"A teacher gives pop quizzes at unpredictable times, so students study consistently — that's a variable-interval schedule." },
  { term:"Fixed ratio", def:"A reinforcement schedule that reinforces a response after a set number of responses.", cat:"Reinforcement Schedules", blank:"set number of responses", accept:["fixed ratio","fixed-ratio schedule","fr"], example:"A coffee shop gives a free drink after every 10 purchases — that's a fixed-ratio schedule." },
  { term:"Variable ratio", def:"A reinforcement schedule that reinforces a response after an unpredictable number of responses, producing high and steady rates of behavior.", cat:"Reinforcement Schedules", blank:"unpredictable number of responses", accept:["variable ratio","variable-ratio schedule","vr"], example:"Slot machines pay out after an unpredictable number of plays, keeping gamblers pulling the lever — that's a variable-ratio schedule." },
  { term:"Scalloped graph", def:"The characteristic pattern of responding on a fixed-interval schedule, showing a pause after reinforcement followed by an increasing rate of responding as the next reinforcement approaches.", cat:"Reinforcement Schedules", blank:"pause after reinforcement", accept:["scalloped graph","scalloped response pattern","scallop effect"], example:"Students study very little right after an exam but cram more and more as the next exam date approaches, creating a scalloped response curve." },

  // ── Developmental Foundations (7) ──
  { term:"Developmental Psychology", def:"The branch of psychology that studies physical, cognitive, and social change throughout the entire life span.", cat:"Developmental Foundations", blank:"entire life span", accept:["developmental psychology"], example:"A developmental psychologist might study how memory ability changes from childhood through old age." },
  { term:"Stability and change", def:"The developmental question of whether personality traits and abilities remain consistent over time or change as we age.", cat:"Developmental Foundations", blank:"remain consistent", accept:["stability and change"], example:"Researchers debate whether a shy toddler will remain introverted as an adult (stability) or become outgoing (change)." },
  { term:"Nature and nurture", def:"The longstanding debate over the relative contributions of biology (genetics) and experience (environment) to development.", cat:"Developmental Foundations", blank:"biology", accept:["nature and nurture","nature vs nurture","nature versus nurture"], example:"Identical twins raised apart help researchers tease apart how much intelligence is genetic (nature) versus shaped by upbringing (nurture)." },
  { term:"Continuous development", def:"The view that development is a gradual, cumulative process of change, like a tree growing taller.", cat:"Developmental Foundations", blank:"gradual, cumulative", accept:["continuous development"], example:"A child's vocabulary grows steadily from a few words to thousands — a gradual, continuous process." },
  { term:"Discontinuous development", def:"The view that development occurs in distinct stages, each qualitatively different from the last, like a caterpillar becoming a butterfly.", cat:"Developmental Foundations", blank:"distinct stages", accept:["discontinuous development"], example:"Piaget's theory describes children as thinking in qualitatively different ways at each stage, not just 'more' — a discontinuous view." },
  { term:"Cross-sectional research", def:"A research method that compares people of different ages at the same point in time.", cat:"Developmental Foundations", blank:"different ages at the same point in time", accept:["cross-sectional research","cross-sectional study","cross sectional"], example:"Comparing memory ability in 20-year-olds, 40-year-olds, and 60-year-olds all tested today is cross-sectional research." },
  { term:"Longitudinal research", def:"A research method that follows the same group of people over an extended period of time to observe changes.", cat:"Developmental Foundations", blank:"same group of people over an extended period", accept:["longitudinal research","longitudinal study","longitudinal"], example:"Tracking the same 100 children from age 5 to age 25 to study how their personalities change is longitudinal research." },

  // ── Physical Development (12) ──
  { term:"Teratogens", def:"Agents such as chemicals, viruses, or radiation that can reach the embryo or fetus during prenatal development and cause harm.", cat:"Physical Development", blank:"chemicals, viruses, or radiation", accept:["teratogens","teratogen"], example:"Alcohol consumed during pregnancy is a teratogen that can cause fetal alcohol syndrome." },
  { term:"Milestones", def:"Key developmental achievements or behaviors that most children reach at roughly predictable ages.", cat:"Physical Development", blank:"predictable ages", accept:["milestones","developmental milestones"], example:"Most babies sit without support around 6 months and walk around 12 months — these are developmental milestones." },
  { term:"Prenatal Development", def:"The development of an organism from conception to birth, progressing through the germinal, embryonic, and fetal stages.", cat:"Physical Development", blank:"conception to birth", accept:["prenatal development"], example:"During the fetal stage of prenatal development, organs mature and the baby gains weight rapidly." },
  { term:"Fine motor coordination", def:"The ability to make precise, small movements using smaller muscle groups, especially in the hands and fingers.", cat:"Physical Development", blank:"small movements", accept:["fine motor coordination","fine motor skills"], example:"A toddler learning to pick up Cheerios with a pincer grasp is developing fine motor coordination." },
  { term:"Gross motor coordination", def:"The ability to make large, whole-body movements using major muscle groups.", cat:"Physical Development", blank:"large, whole-body movements", accept:["gross motor coordination","gross motor skills"], example:"A baby learning to crawl, stand, and eventually walk is developing gross motor coordination." },
  { term:"Maturation", def:"The orderly sequence of biological growth and development that is largely determined by genetic processes.", cat:"Physical Development", blank:"biological growth", accept:["maturation"], example:"Children around the world begin walking at roughly the same age regardless of practice, because walking depends on neural maturation." },
  { term:"Reflexes", def:"Automatic, involuntary responses to stimuli that are present at birth and support survival.", cat:"Physical Development", blank:"automatic, involuntary", accept:["reflexes","reflex"], example:"A newborn automatically grasps anything placed in its palm — the palmar grasp reflex." },
  { term:"Rooting reflex", def:"A newborn's tendency to turn the head and open the mouth in the direction of a touch on the cheek, aiding in feeding.", cat:"Physical Development", blank:"turn the head", accept:["rooting reflex","rooting"], example:"When you stroke a newborn's cheek, the baby turns toward your finger and opens its mouth, searching for a nipple." },
  { term:"Visual cliff", def:"A laboratory apparatus designed by Gibson and Walk to test depth perception in infants, using a glass surface over an apparent drop-off.", cat:"Physical Development", blank:"depth perception", accept:["visual cliff"], example:"Most crawling infants refuse to cross the 'deep' side of the visual cliff, showing they perceive depth." },
  { term:"Critical periods", def:"Specific time windows during development when an organism is especially receptive to certain environmental influences; missing the window may make later learning impossible.", cat:"Physical Development", blank:"especially receptive", accept:["critical periods","critical period"], example:"If a kitten's eye is sewn shut during the critical period for visual development, normal vision in that eye may never develop." },
  { term:"Sensitive periods", def:"Optimal time periods when an organism is particularly responsive to certain stimuli, but development can still occur outside this window, though with more difficulty.", cat:"Physical Development", blank:"optimal time periods", accept:["sensitive periods","sensitive period"], example:"Children who are not exposed to language before puberty can still learn some language, but with great difficulty — the sensitive period has passed." },
  { term:"Imprinting", def:"A rapid, innate form of learning that occurs during a critical period shortly after birth, in which an organism forms an attachment to the first moving object it sees.", cat:"Physical Development", blank:"first moving object", accept:["imprinting"], example:"Konrad Lorenz demonstrated that newborn goslings would follow him as if he were their mother because he was the first moving thing they saw." },

  // ── Puberty & Gender (10) ──
  { term:"Growth Spurt", def:"A period of rapid physical growth in height and weight that occurs during puberty.", cat:"Puberty & Gender", blank:"rapid physical growth", accept:["growth spurt"], example:"A 13-year-old boy grows four inches in one year during his adolescent growth spurt." },
  { term:"Puberty", def:"The period of sexual maturation during which a person becomes capable of reproduction, marked by hormonal changes and physical development.", cat:"Puberty & Gender", blank:"sexual maturation", accept:["puberty"], example:"During puberty, rising levels of estrogen and testosterone trigger the development of secondary sex characteristics." },
  { term:"Primary sex characteristics", def:"The reproductive organs and structures that are directly involved in reproduction, such as the ovaries, testes, and uterus.", cat:"Puberty & Gender", blank:"reproductive organs", accept:["primary sex characteristics"], example:"The maturation of the ovaries in girls and testes in boys during puberty are changes in primary sex characteristics." },
  { term:"Secondary sex characteristics", def:"Non-reproductive physical features that develop during puberty, such as breast development, facial hair, and voice deepening.", cat:"Puberty & Gender", blank:"non-reproductive physical features", accept:["secondary sex characteristics"], example:"A boy's voice deepening and a girl's hips widening are secondary sex characteristics — not directly involved in reproduction." },
  { term:"Menarche", def:"A female's first menstrual period, marking the onset of reproductive capability.", cat:"Puberty & Gender", blank:"first menstrual period", accept:["menarche"], example:"In the United States, the average age of menarche is around 12–13 years old." },
  { term:"Spermarche", def:"A male's first ejaculation, typically occurring around age 13, marking the onset of reproductive capability.", cat:"Puberty & Gender", blank:"first ejaculation", accept:["spermarche"], example:"Spermarche often occurs during sleep (a nocturnal emission) and signals that a boy has reached reproductive maturity." },
  { term:"Menopause", def:"The cessation of menstruation and the end of a woman's reproductive capability, typically occurring in the late 40s or early 50s.", cat:"Puberty & Gender", blank:"cessation of menstruation", accept:["menopause"], example:"A 52-year-old woman who has not had a menstrual period for a year has reached menopause." },
  { term:"Sex", def:"In psychology, the biologically defined category of male or female based on chromosomes, hormones, and reproductive anatomy.", cat:"Puberty & Gender", blank:"biologically defined", accept:["sex","biological sex"], example:"A person's sex is typically classified at birth based on physical anatomy as male or female." },
  { term:"Gender", def:"The socially constructed roles, behaviors, and attributes that a society considers appropriate for males and females.", cat:"Puberty & Gender", blank:"socially constructed", accept:["gender"], example:"In some cultures, men are expected to be stoic and women nurturing — these are gender role expectations, not biological requirements." },
  { term:"Socialization", def:"The lifelong process by which individuals learn the norms, values, and behaviors expected by their culture and social groups.", cat:"Puberty & Gender", blank:"norms, values, and behaviors", accept:["socialization"], example:"A child learns to say 'please' and 'thank you' through socialization — family, school, and peers all shape behavior." },

  // ── Piaget's Stages (15) ──
  { term:"Jean Piaget", def:"Swiss developmental psychologist who proposed a stage theory of cognitive development, arguing that children actively construct their understanding of the world through four stages.", cat:"Piaget's Stages", blank:"stage theory of cognitive development", accept:["jean piaget","piaget"], example:"Piaget observed his own children and proposed that children think qualitatively differently from adults, not just 'less.'" },
  { term:"Schemas", def:"Mental frameworks or concepts that organize and interpret information, helping us process and understand new experiences.", cat:"Piaget's Stages", blank:"mental frameworks", accept:["schemas","schema","schemata"], example:"A toddler's schema for 'dog' includes four legs and fur — they might call a cat a 'doggy' at first." },
  { term:"Assimilation", def:"In Piaget's theory, interpreting new experiences in terms of existing schemas.", cat:"Piaget's Stages", blank:"existing schemas", accept:["assimilation"], example:"A child who calls every four-legged animal a 'doggy' is assimilating new animals into their existing dog schema." },
  { term:"Accommodation", def:"In Piaget's theory, adapting existing schemas or creating new ones to incorporate new information that doesn't fit.", cat:"Piaget's Stages", blank:"adapting existing schemas", accept:["accommodation"], example:"When a child learns that cats are different from dogs, they accommodate by creating a new 'cat' schema." },
  { term:"Sensorimotor stage", def:"Piaget's first stage of cognitive development (birth to about age 2) during which infants know the world through their sensory impressions and motor activities.", cat:"Piaget's Stages", blank:"sensory impressions and motor activities", accept:["sensorimotor stage","sensorimotor"], example:"A baby shaking a rattle to hear the sound and putting everything in their mouth is exploring the world through the sensorimotor stage." },
  { term:"Object permanence", def:"The understanding that objects continue to exist even when they cannot be seen, heard, or otherwise sensed; develops during the sensorimotor stage.", cat:"Piaget's Stages", blank:"continue to exist", accept:["object permanence"], example:"Before developing object permanence, a baby thinks a toy hidden under a blanket has ceased to exist." },
  { term:"Preoperational stage", def:"Piaget's second stage (ages 2 to about 7) during which a child learns to use language and think symbolically, but cannot yet perform logical mental operations.", cat:"Piaget's Stages", blank:"think symbolically", accept:["preoperational stage","preoperational"], example:"A 4-year-old can pretend a stick is a sword (symbolic thinking) but cannot understand that pouring water into a taller glass doesn't change the amount." },
  { term:"Mental symbols", def:"Internal representations such as words, images, or mental models that stand for objects, events, or concepts not currently present.", cat:"Piaget's Stages", blank:"internal representations", accept:["mental symbols","symbolic representation"], example:"A child drawing a picture of their family uses mental symbols — the stick figures represent real people." },
  { term:"Pretend play", def:"A form of symbolic play in which children use objects, actions, or ideas to represent other objects, actions, or ideas; emerges in the preoperational stage.", cat:"Piaget's Stages", blank:"symbolic play", accept:["pretend play","imaginative play","symbolic play"], example:"A 3-year-old uses a banana as a pretend telephone, demonstrating the ability to use symbols." },
  { term:"Conservation", def:"The understanding that certain physical properties of objects (such as mass, volume, and number) remain the same even when their outward appearance changes.", cat:"Piaget's Stages", blank:"remain the same", accept:["conservation"], example:"A preoperational child thinks a tall, narrow glass holds more water than a short, wide glass — they haven't yet grasped conservation." },
  { term:"Reversibility", def:"The understanding that objects can be changed and then returned to their original state; a cognitive ability gained in the concrete operational stage.", cat:"Piaget's Stages", blank:"returned to their original state", accept:["reversibility"], example:"A child who understands that flattened clay can be rolled back into a ball grasps reversibility." },
  { term:"Animism", def:"The belief, common in preoperational children, that inanimate objects have lifelike qualities such as feelings and intentions.", cat:"Piaget's Stages", blank:"inanimate objects have lifelike qualities", accept:["animism"], example:"A 3-year-old says 'the sun is happy today' because they believe the sun has feelings." },
  { term:"Egocentrism", def:"In Piaget's theory, the preoperational child's difficulty seeing things from another person's point of view.", cat:"Piaget's Stages", blank:"another person's point of view", accept:["egocentrism"], example:"A child covers their own eyes and says 'you can't see me!' — assuming others share their visual perspective." },
  { term:"Theory of mind", def:"The ability to understand that others have their own thoughts, beliefs, desires, and intentions that may differ from one's own.", cat:"Piaget's Stages", blank:"others have their own thoughts", accept:["theory of mind","tom"], example:"A 5-year-old understands that if their friend didn't see the candy being moved, the friend will look in the original location — a false-belief task." },
  { term:"Concrete operational stage", def:"Piaget's third stage (ages 7 to about 11) during which children gain the mental ability to comprehend logical operations with concrete (tangible) objects but struggle with abstract reasoning.", cat:"Piaget's Stages", blank:"concrete (tangible) objects", accept:["concrete operational stage","concrete operational"], example:"A 9-year-old can correctly sort animals by multiple categories (habitat and diet) but struggles with hypothetical 'what if' scenarios." },
  { term:"Formal operational stage", def:"Piaget's fourth and final stage (age 12 and up) during which people begin to think logically about abstract concepts and engage in hypothetical and deductive reasoning.", cat:"Piaget's Stages", blank:"abstract concepts", accept:["formal operational stage","formal operational"], example:"A teenager can reason about justice, morality, and hypothetical situations like 'What would happen if gravity didn't exist?'" },

  // ── Vygotsky & Intelligence (6) ──
  { term:"Lev Vygotsky", def:"Russian psychologist who emphasized the role of social interaction and culture in cognitive development, proposing that learning occurs through guided participation with more knowledgeable others.", cat:"Vygotsky & Intelligence", blank:"social interaction and culture", accept:["lev vygotsky","vygotsky"], example:"Vygotsky argued that a child learns more when working with a skilled tutor than when working alone." },
  { term:"Scaffolding (as it pertains to Vygotsky)", def:"A process in which a more knowledgeable person provides temporary support and guidance to help a learner accomplish a task they cannot yet do independently.", cat:"Vygotsky & Intelligence", blank:"temporary support and guidance", accept:["scaffolding","vygotsky scaffolding"], example:"A parent helps a child complete a puzzle by pointing to where pieces go, gradually offering less help as the child improves." },
  { term:"Zone of proximal development", def:"The range of tasks that a learner cannot yet do alone but can accomplish with the guidance of a more skilled partner.", cat:"Vygotsky & Intelligence", blank:"cannot yet do alone", accept:["zone of proximal development","zpd"], example:"A child can't solve long division alone but can with teacher guidance — long division is in their zone of proximal development." },
  { term:"Crystallized intelligence", def:"Accumulated knowledge, vocabulary, and skills that come from experience and education; tends to increase with age.", cat:"Vygotsky & Intelligence", blank:"accumulated knowledge", accept:["crystallized intelligence"], example:"A 70-year-old professor's vast vocabulary and deep subject expertise reflect high crystallized intelligence." },
  { term:"Fluid intelligence", def:"The ability to reason quickly, think abstractly, and solve novel problems independent of prior knowledge; tends to decline with age.", cat:"Vygotsky & Intelligence", blank:"reason quickly", accept:["fluid intelligence"], example:"Solving a new type of logic puzzle you've never seen before relies on fluid intelligence." },
  { term:"Dementia", def:"A set of symptoms involving a progressive decline in cognitive functions — including memory, reasoning, and communication — severe enough to interfere with daily life.", cat:"Vygotsky & Intelligence", blank:"progressive decline", accept:["dementia"], example:"An elderly man who increasingly forgets familiar faces, gets lost driving home, and cannot manage his finances may be experiencing dementia." },

  // ── Language Development (12) ──
  { term:"Language", def:"A system of symbols (words, gestures, or sounds) and rules for combining them to communicate meaning.", cat:"Language Development", blank:"system of symbols", accept:["language"], example:"English, American Sign Language, and Mandarin are all languages — each has vocabulary and grammatical rules." },
  { term:"Phonemes", def:"The smallest distinctive units of sound in a language that distinguish one word from another.", cat:"Language Development", blank:"smallest distinctive units of sound", accept:["phonemes","phoneme"], example:"The words 'bat' and 'pat' differ by one phoneme — the initial /b/ versus /p/ sound." },
  { term:"Morphemes", def:"The smallest units of language that carry meaning, including prefixes, suffixes, and root words.", cat:"Language Development", blank:"smallest units of language that carry meaning", accept:["morphemes","morpheme"], example:"The word 'unhappiness' contains three morphemes: 'un-' (not), 'happy' (feeling), and '-ness' (state of)." },
  { term:"Semantics", def:"The set of rules governing the meaning of words and sentences in a language.", cat:"Language Development", blank:"meaning of words", accept:["semantics"], example:"Understanding that 'I'm feeling blue' means sad (not the color) requires knowledge of semantics." },
  { term:"Grammar", def:"The system of rules that governs how words are arranged into sentences in a language, encompassing both syntax and semantics.", cat:"Language Development", blank:"rules that governs how words are arranged", accept:["grammar"], example:"'The dog bit the man' and 'The man bit the dog' have very different meanings because of grammar." },
  { term:"Syntax", def:"The rules for combining words into grammatically correct sentences — the order and structure of language.", cat:"Language Development", blank:"combining words", accept:["syntax"], example:"In English, 'She kicked the ball' follows correct syntax, while 'Ball the kicked she' does not." },
  { term:"Nonverbal Gestures", def:"Body movements, facial expressions, and hand signals used to communicate meaning without words.", cat:"Language Development", blank:"without words", accept:["nonverbal gestures","gestures","nonverbal communication"], example:"A baby waving 'bye-bye' or pointing at a cookie to request it is using nonverbal gestures before speaking." },
  { term:"Cooing", def:"An early stage of language development (around 2–4 months) in which infants produce vowel-like sounds such as 'oooh' and 'aaah.'", cat:"Language Development", blank:"vowel-like sounds", accept:["cooing"], example:"A 3-month-old lying in a crib making 'ooo' and 'aaa' sounds is cooing." },
  { term:"Babbling", def:"A stage of language development (around 4–10 months) in which infants spontaneously produce a variety of consonant-vowel combinations like 'bababa' and 'dadada.'", cat:"Language Development", blank:"consonant-vowel combinations", accept:["babbling"], example:"A 6-month-old repeatedly saying 'mamama' and 'bababa' is in the babbling stage — these sounds aren't yet meaningful words." },
  { term:"One-word stage", def:"A stage of language development (around 1–2 years) in which a child speaks mostly in single words that often carry the meaning of a whole sentence.", cat:"Language Development", blank:"single words", accept:["one-word stage","holophrastic stage"], example:"A toddler saying 'milk!' to mean 'I want milk' is in the one-word (holophrastic) stage." },
  { term:"Telegraphic speech", def:"An early stage of language development (around age 2) in which a child speaks in two-word phrases that convey meaning like a telegram, using mostly nouns and verbs.", cat:"Language Development", blank:"two-word phrases", accept:["telegraphic speech"], example:"A 2-year-old saying 'want cookie' or 'mommy go' is using telegraphic speech — short but meaningful." },
  { term:"Overgeneralization of language rules", def:"The tendency of young children to apply grammatical rules too broadly, producing incorrect forms like 'goed' instead of 'went.'", cat:"Language Development", blank:"apply grammatical rules too broadly", accept:["overgeneralization","overregularization","overgeneralization of language rules"], example:"A child says 'I runned fast' instead of 'I ran fast,' applying the regular past-tense '-ed' rule to an irregular verb." },

  // ── Ecological Systems (6) ──
  { term:"Ecological systems theory", def:"Bronfenbrenner's theory that development is shaped by the interaction of multiple nested environmental systems, from immediate settings to broad cultural values.", cat:"Ecological Systems", blank:"nested environmental systems", accept:["ecological systems theory","bronfenbrenner's theory","bioecological model"], example:"A child's development is shaped not only by family (microsystem) but also by the parents' workplace policies (exosystem) and cultural attitudes (macrosystem)." },
  { term:"Microsystem", def:"In Bronfenbrenner's theory, the innermost system — the direct environments in which a person has face-to-face interactions, such as family, school, and peers.", cat:"Ecological Systems", blank:"direct environments", accept:["microsystem"], example:"A child's daily interactions with parents at home and teachers at school are part of their microsystem." },
  { term:"Mesosystem", def:"In Bronfenbrenner's theory, the connections and interactions between two or more microsystems, such as the relationship between a child's home and school.", cat:"Ecological Systems", blank:"connections and interactions between", accept:["mesosystem"], example:"A parent-teacher conference represents the mesosystem — the link between the home and school microsystems." },
  { term:"Exosystem", def:"In Bronfenbrenner's theory, the settings that the individual does not directly participate in but that still affect their development, such as a parent's workplace.", cat:"Ecological Systems", blank:"does not directly participate in", accept:["exosystem"], example:"A parent's stressful job (which the child never visits) affects the parent's mood at home, indirectly influencing the child's development." },
  { term:"Macrosystem", def:"In Bronfenbrenner's theory, the outermost layer consisting of the cultural values, laws, customs, and resources of the society in which a person lives.", cat:"Ecological Systems", blank:"cultural values", accept:["macrosystem"], example:"Growing up in a culture that values education influences a family's emphasis on schoolwork — that's the macrosystem at work." },
  { term:"Chronosystem", def:"In Bronfenbrenner's theory, the dimension of time — historical events, life transitions, and sociohistorical conditions that influence development.", cat:"Ecological Systems", blank:"dimension of time", accept:["chronosystem"], example:"A child growing up during the COVID-19 pandemic experienced unique developmental challenges due to their chronosystem." },

  // ── Parenting & Attachment (12) ──
  { term:"Authoritarian parenting", def:"A parenting style characterized by strict rules, high demands, and little warmth or responsiveness; parents expect obedience without explanation.", cat:"Parenting & Attachment", blank:"strict rules", accept:["authoritarian parenting","authoritarian"], example:"A parent who says 'Because I said so!' and punishes any questioning of rules is demonstrating authoritarian parenting." },
  { term:"Authoritative parenting", def:"A parenting style characterized by high demands combined with high warmth and responsiveness; parents set clear rules but encourage open discussion.", cat:"Parenting & Attachment", blank:"high demands combined with high warmth", accept:["authoritative parenting","authoritative"], example:"A parent who explains why a curfew exists, listens to their teen's perspective, but still enforces the rule is authoritative." },
  { term:"Permissive parenting", def:"A parenting style characterized by few demands and high responsiveness; parents are warm and accepting but provide little discipline or structure.", cat:"Parenting & Attachment", blank:"few demands", accept:["permissive parenting","permissive"], example:"A parent who lets their child eat whatever they want, stay up as late as they want, and rarely enforces rules is permissive." },
  { term:"Attachment styles", def:"Patterns of emotional bonding between infants and caregivers, classified by Ainsworth using the Strange Situation as secure, avoidant, anxious, or disorganized.", cat:"Parenting & Attachment", blank:"emotional bonding", accept:["attachment styles","attachment"], example:"Ainsworth's Strange Situation observed how infants reacted when their mother left and returned to classify attachment styles." },
  { term:"Secure attachment", def:"An attachment style in which a child explores freely when the caregiver is present, shows distress upon separation, and is easily comforted upon the caregiver's return.", cat:"Parenting & Attachment", blank:"easily comforted", accept:["secure attachment"], example:"A securely attached toddler cries when mom leaves the room but quickly calms down and resumes play when she returns." },
  { term:"Insecure attachment", def:"A general term for attachment styles in which the bond between child and caregiver is characterized by anxiety, avoidance, or inconsistency, rather than trust and security.", cat:"Parenting & Attachment", blank:"anxiety, avoidance, or inconsistency", accept:["insecure attachment"], example:"A child who either clings desperately to a caregiver or avoids them altogether may have an insecure attachment." },
  { term:"Avoidant attachment", def:"An insecure attachment style in which the child shows little distress when the caregiver leaves and avoids or ignores the caregiver upon return.", cat:"Parenting & Attachment", blank:"avoids or ignores", accept:["avoidant attachment","insecure-avoidant"], example:"A toddler doesn't seem to care when mom leaves and turns away when she comes back — this child shows avoidant attachment." },
  { term:"Anxious attachment", def:"An insecure attachment style in which the child shows intense distress when the caregiver leaves and is difficult to comfort upon return, clinging yet also resisting contact.", cat:"Parenting & Attachment", blank:"intense distress", accept:["anxious attachment","anxious-ambivalent attachment","ambivalent attachment","resistant attachment"], example:"A toddler screams when mom leaves and clings to her when she returns but also pushes her away — anxious/ambivalent attachment." },
  { term:"Disorganized attachment", def:"An insecure attachment style marked by confused, contradictory behavior toward the caregiver, often resulting from frightening or abusive caregiving.", cat:"Parenting & Attachment", blank:"confused, contradictory behavior", accept:["disorganized attachment","disorganized-disoriented attachment"], example:"A child approaches the returning caregiver but then freezes, looks away, or falls to the floor — showing disorganized attachment." },
  { term:"Temperament", def:"A person's characteristic emotional reactivity and intensity, which is largely biologically based and present from birth.", cat:"Parenting & Attachment", blank:"emotional reactivity", accept:["temperament"], example:"Some babies are naturally calm and adaptable ('easy' temperament) while others are fussy and slow to warm up, even from day one." },
  { term:"Separation anxiety", def:"The distress displayed by infants and toddlers when separated from their primary caregiver, typically peaking around 12–18 months.", cat:"Parenting & Attachment", blank:"distress", accept:["separation anxiety"], example:"An 8-month-old wails when dropped off at daycare because they haven't yet learned that mom will come back." },
  { term:"Contact comfort", def:"Harlow's finding that infant monkeys preferred a soft, cloth 'mother' over a wire 'mother' that provided food, showing that attachment is based on more than just feeding.", cat:"Parenting & Attachment", blank:"soft, cloth", accept:["contact comfort"], example:"Harlow's monkeys clung to the soft terrycloth surrogate mother for comfort, even though the wire mother had the food bottle." },

  // ── Social Development (5) ──
  { term:"Parallel play", def:"A stage of play in which children play alongside but not interactively with one another, each engaged in their own activity.", cat:"Social Development", blank:"alongside but not interactively", accept:["parallel play"], example:"Two 2-year-olds sit next to each other at a sandbox, each building their own structure without interacting — that's parallel play." },
  { term:"Imaginary audience", def:"An adolescent's belief that others are constantly watching and evaluating them, contributing to heightened self-consciousness.", cat:"Social Development", blank:"constantly watching", accept:["imaginary audience"], example:"A teenager is mortified by a small pimple, convinced that everyone at school will notice and judge them." },
  { term:"Personal fable", def:"An adolescent's belief that their experiences and feelings are unique and that they are invulnerable to harm.", cat:"Social Development", blank:"unique and that they are invulnerable", accept:["personal fable"], example:"A teenager says 'You don't understand what I'm going through — no one has ever felt this way!' — a classic personal fable." },
  { term:"Social clock", def:"The culturally preferred timing of social events such as marriage, parenthood, and retirement.", cat:"Social Development", blank:"culturally preferred timing", accept:["social clock"], example:"Feeling pressure to be married by 30 or to have a career established by 25 reflects the social clock." },
  { term:"Emerging adulthood", def:"A developmental stage proposed by Arnett, spanning ages 18 to 25, characterized by identity exploration, instability, and feeling 'in between' adolescence and full adulthood.", cat:"Social Development", blank:"identity exploration", accept:["emerging adulthood"], example:"A 22-year-old college graduate who is still figuring out their career, relationships, and identity is in emerging adulthood." },

  // ── Erikson's Stages (9) ──
  { term:"Stage theory of psychosocial development (Erikson)", def:"Erikson's theory that personality develops through eight stages across the lifespan, each involving a psychosocial crisis that must be resolved.", cat:"Erikson's Stages", blank:"eight stages", accept:["erikson's stages","erikson's theory","psychosocial development","erikson"], example:"Unlike Freud, Erikson believed development continues throughout life — an 80-year-old still faces a developmental crisis (integrity vs. despair)." },
  { term:"Trust and mistrust", def:"Erikson's first psychosocial stage (birth to ~1 year) in which infants learn to trust or mistrust their caregivers based on the consistency of care.", cat:"Erikson's Stages", blank:"trust or mistrust", accept:["trust vs mistrust","trust and mistrust","trust versus mistrust"], example:"An infant whose cries are consistently answered with feeding and comfort develops a sense of basic trust." },
  { term:"Autonomy and shame and doubt", def:"Erikson's second psychosocial stage (~1–3 years) in which toddlers learn to exercise their will and do things for themselves, or develop shame and doubt about their abilities.", cat:"Erikson's Stages", blank:"exercise their will", accept:["autonomy vs shame and doubt","autonomy and shame and doubt","autonomy versus shame"], example:"A toddler who insists on dressing themselves — even if the shirt is on backwards — is asserting autonomy." },
  { term:"Initiative and guilt", def:"Erikson's third psychosocial stage (~3–6 years) in which children learn to initiate tasks and carry out plans, or feel guilty about their efforts to be independent.", cat:"Erikson's Stages", blank:"initiate tasks", accept:["initiative vs guilt","initiative and guilt","initiative versus guilt"], example:"A preschooler who organizes a game of pretend with friends is showing initiative." },
  { term:"Industry and inferiority", def:"Erikson's fourth psychosocial stage (~6–12 years) in which children learn the pleasure of applying themselves to tasks, or feel inferior if they fail.", cat:"Erikson's Stages", blank:"applying themselves to tasks", accept:["industry vs inferiority","industry and inferiority","industry versus inferiority"], example:"A child who takes pride in building a complex LEGO set is developing a sense of industry." },
  { term:"Identity and role confusion", def:"Erikson's fifth psychosocial stage (adolescence) in which teens work to establish a sense of self and personal identity, or become confused about who they are and their role in society.", cat:"Erikson's Stages", blank:"sense of self", accept:["identity vs role confusion","identity and role confusion","identity versus role confusion"], example:"A teenager experimenting with different friend groups, clothing styles, and beliefs is working through identity vs. role confusion." },
  { term:"Intimacy and isolation", def:"Erikson's sixth psychosocial stage (young adulthood) in which young adults form close, committed relationships, or experience isolation and loneliness.", cat:"Erikson's Stages", blank:"close, committed relationships", accept:["intimacy vs isolation","intimacy and isolation","intimacy versus isolation"], example:"A young adult who builds a deep, loving partnership has resolved the intimacy vs. isolation crisis." },
  { term:"Generativity and stagnation", def:"Erikson's seventh psychosocial stage (middle adulthood) in which adults contribute to the next generation through parenting, work, or mentoring, or feel a lack of purpose.", cat:"Erikson's Stages", blank:"contribute to the next generation", accept:["generativity vs stagnation","generativity and stagnation","generativity versus stagnation"], example:"A middle-aged mentor who guides young professionals feels a sense of generativity." },
  { term:"Integrity and despair", def:"Erikson's eighth psychosocial stage (late adulthood) in which older adults reflect on their lives with a sense of satisfaction (integrity) or regret (despair).", cat:"Erikson's Stages", blank:"reflect on their lives", accept:["integrity vs despair","integrity and despair","integrity versus despair","ego integrity vs despair"], example:"An elderly person who looks back and says 'I lived a good life' has achieved integrity; one filled with regret experiences despair." },

  // ── Identity Development (11) ──
  { term:"Adverse childhood experiences (ACEs)", def:"Potentially traumatic events that occur before age 18 — including abuse, neglect, and household dysfunction — that are linked to negative health and developmental outcomes later in life.", cat:"Identity Development", blank:"potentially traumatic events", accept:["adverse childhood experiences","aces","adverse childhood experiences (aces)"], example:"A child who grows up witnessing domestic violence and parental substance abuse has multiple ACEs, increasing their risk for depression and chronic illness." },
  { term:"Achievement (adolescent development)", def:"In Marcia's identity status theory, the status in which an adolescent has explored identity options and made a firm commitment to a set of values, goals, or beliefs.", cat:"Identity Development", blank:"explored identity options and made a firm commitment", accept:["achievement","identity achievement"], example:"A student who explored several career paths and chose to pursue medicine with confidence has reached identity achievement." },
  { term:"Diffusion (adolescent development)", def:"In Marcia's identity status theory, the status in which an adolescent has neither explored nor committed to any identity, showing apathy or lack of direction.", cat:"Identity Development", blank:"neither explored nor committed", accept:["diffusion","identity diffusion"], example:"A teenager who has no career goals, hasn't thought about their values, and isn't concerned about it is in identity diffusion." },
  { term:"Foreclosure (adolescent development)", def:"In Marcia's identity status theory, the status in which an adolescent has committed to an identity without exploring alternatives, often adopting the values of parents or authority figures.", cat:"Identity Development", blank:"without exploring alternatives", accept:["foreclosure","identity foreclosure"], example:"A teenager who says 'I'm going to be a lawyer because my dad is one' without ever considering other options is in foreclosure." },
  { term:"Moratorium (adolescent development)", def:"In Marcia's identity status theory, the status in which an adolescent is actively exploring identity options but has not yet made a commitment.", cat:"Identity Development", blank:"actively exploring", accept:["moratorium","identity moratorium"], example:"A college student who keeps changing majors and trying different activities is in moratorium — still searching for their identity." },
  { term:"Racial/ethnic identity", def:"An individual's sense of belonging to a particular racial or ethnic group and the feelings, attitudes, and beliefs associated with that membership.", cat:"Identity Development", blank:"sense of belonging", accept:["racial/ethnic identity","racial identity","ethnic identity"], example:"A biracial teenager exploring what it means to identify with both their Black and White heritage is developing their racial/ethnic identity." },
  { term:"Sexual orientation", def:"An enduring pattern of emotional, romantic, and/or sexual attraction to people of a particular gender or genders.", cat:"Identity Development", blank:"enduring pattern", accept:["sexual orientation"], example:"A person who is consistently attracted to people of the opposite sex has a heterosexual orientation." },
  { term:"Religious identity", def:"An individual's sense of belonging to a religious group or tradition and the values, beliefs, and practices they adopt as part of that identity.", cat:"Identity Development", blank:"religious group or tradition", accept:["religious identity"], example:"A teenager raised Catholic who questions and then reaffirms their faith is developing their religious identity." },
  { term:"Occupational identity", def:"An individual's self-concept as it relates to their chosen career or professional role.", cat:"Identity Development", blank:"chosen career", accept:["occupational identity","vocational identity"], example:"A medical student who strongly identifies as a 'future doctor' has developed an occupational identity." },
  { term:"Familial identity", def:"An individual's sense of self as shaped by their family roles, relationships, and the values transmitted within their family.", cat:"Identity Development", blank:"family roles", accept:["familial identity"], example:"A teenager who takes pride in being the eldest sibling and carrying on family traditions has a strong familial identity." },
  { term:"Possible selves", def:"Future-oriented representations of what a person hopes to become, expects to become, or fears becoming, which motivate current behavior.", cat:"Identity Development", blank:"hopes to become", accept:["possible selves","possible self"], example:"A high schooler imagines becoming a successful scientist (hoped-for self) and a dropout (feared self) — both images motivate studying." },
];

export const CATEGORIES = [...new Set(TERMS.map(t => t.cat))];

// Commonly confused pairs for Compare & Contrast mode
export const CONFUSED_PAIRS = [
  ["Classical conditioning", "Operant conditioning"],
  ["Positive reinforcement", "Negative reinforcement"],
  ["Positive punishment", "Negative punishment"],
  ["Unconditioned stimulus (UCS)", "Conditioned stimulus (CS)"],
  ["Unconditioned response (UR)", "Conditioned response (CR)"],
  ["Extinction", "Habituation"],
  ["Stimulus discrimination", "Stimulus generalization"],
  ["Assimilation", "Accommodation"],
  ["Authoritarian parenting", "Authoritative parenting"],
  ["Secure attachment", "Insecure attachment"],
  ["Continuous development", "Discontinuous development"],
  ["Cross-sectional research", "Longitudinal research"],
  ["Critical periods", "Sensitive periods"],
  ["Primary sex characteristics", "Secondary sex characteristics"],
  ["Menarche", "Spermarche"],
  ["Sex", "Gender"],
  ["Phonemes", "Morphemes"],
  ["Semantics", "Syntax"],
  ["Crystallized intelligence", "Fluid intelligence"],
  ["Sensorimotor stage", "Preoperational stage"],
  ["Concrete operational stage", "Formal operational stage"],
  ["Zone of proximal development", "Scaffolding (as it pertains to Vygotsky)"],
  ["Fixed interval", "Variable interval"],
  ["Fixed ratio", "Variable ratio"],
  ["Continuous reinforcement", "Partial reinforcement"],
  ["Primary reinforcers", "Secondary reinforcers"],
  ["Modeling", "Vicarious conditioning"],
  ["Latent learning", "Insight learning"],
  ["Avoidant attachment", "Anxious attachment"],
  ["Imaginary audience", "Personal fable"],
];

export function getTermByName(name) {
  return TERMS.find(t => t.term === name);
}
